&lt;strong&gt;&lt;span style=&quot;font-size: 21px;&quot;&gt;मुख्य बिंदु&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;जौ की किस्में-&lt;/strong&gt;

	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;​&lt;/strong&gt;DWRB - 52, &amp;nbsp;DL - 83,&amp;nbsp;&lt;strong&gt;R&lt;/strong&gt;&lt;strong&gt;D - 2035&lt;/strong&gt;,&amp;nbsp; RD - 2668, RD - 2503, D W R - 28, RD - 2552, BH - 902, PL - 426 (पंजाब), RD - 2592 (राजस्थान) आदि किस्में&amp;nbsp;प्रमुख हैं।&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;बाजरा की किस्में -​&lt;/strong&gt;
	&lt;ul&gt;
		&lt;li&gt;&lt;strong&gt;​&lt;/strong&gt;राज 171, पूसा 322, AHB 1200, GHB 732, पूसा 23, GHB 719, RS.B 177,&lt;strong&gt;RHB-30,&lt;/strong&gt; MPMH 21, BD- 111, BJ-104, HB2, HB3, MBH15 आदि।&amp;nbsp;&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;मक्का की किस्में-​&lt;/strong&gt;
	&lt;ul&gt;
