			&lt;p align=&quot;center&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;फसलें&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 33px;&quot;&gt;
			&lt;p align=&quot;center&quot;&gt;&amp;nbsp;&lt;/p&gt;
