			&lt;/td&gt;
			&lt;td style=&quot;width: 55px;&quot;&gt;
			&lt;p&gt;ज्वार&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 33px;&quot;&gt;
			&lt;p&gt;I.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 116px;&quot;&gt;
			&lt;p&gt;मध्यप्रदेश&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 37px;&quot;&gt;
			&lt;p&gt;B.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 55px;&quot;&gt;
			&lt;p&gt;बाजरा&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 33px;&quot;&gt;
			&lt;p&gt;II.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 116px;&quot;&gt;
			&lt;p&gt;महाराष्ट्र&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 37px;&quot;&gt;
			&lt;p&gt;C.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 55px;&quot;&gt;
			&lt;p&gt;चावल&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 33px;&quot;&gt;
			&lt;p&gt;III.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 116px;&quot;&gt;
			&lt;p&gt;राजस्थान&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;width: 37px;&quot;&gt;
			&lt;p&gt;D.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 55px;&quot;&gt;
			&lt;p&gt;चना&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 33px;&quot;&gt;
			&lt;p&gt;IV.&lt;/p&gt;
			&lt;/td&gt;
			&lt;td style=&quot;width: 116px;&quot;&gt;
			&lt;p&gt;पश्चिम बंगाल&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
&lt;/table&gt;

&lt;p style=&quot;&quot;&gt;नीचे दिए&amp;nbsp;गए&amp;nbsp;विकल्पों में से सही उत्तर का चयन कीजिए।&amp;nbsp;&lt;/p&gt;<br>&lt;p&gt;Match the crop with the State that is its leading producer.&lt;/p&gt;

&lt;table border=&quot;1&quot; cellpadding=&quot;1&quot; cellspacing=&quot;1&quot; style=&quot;width:300px;&quot;&gt;
	&lt;tbody&gt;
		&lt;tr&gt;
			&lt;td&gt;&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700; text-align: -webkit-center; &quot;&gt;Crops&lt;/span&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&amp;nbsp;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700; text-align: -webkit-center; &quot;&gt;Leading Producer&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;A.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Jowar&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;1.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Madhya Pradesh&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;B.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Bajra&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;2.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Maharashtra&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;C.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Rice&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;3.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Rajasthan&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;D.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;Gram&lt;/span&gt;&lt;/td&gt;
			&lt;td&gt;4.&lt;/td&gt;
			&lt;td&gt;&lt;span style=&quot;&quot;&gt;West Bengal&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
	&lt;/tbody&gt;
